			this.loadingIndicator.reset();

			const diagnosticEvent = event as Proto.DiagnosticEvent;
			if (diagnosticEvent.body?.diagnostics) {
				this._onDiagnosticsReceived.fire({
					kind: getDiagnosticsKind(event),
